 1→import { z } from "zod";
 2→import { ENTITY_CATEGORIES } from "../../shared/contracts";
 3→
 4→// Azure structured output requires all properties in `required` — no optional fields allowed.
 5→// Use "none" sentinel in the extraction schema, then strip it to undefined after parsing.
 6→const extractionCategorySchema = z.enum([...ENTITY_CATEGORIES, "none"]).transform(
 7→  (v) => (v === "none" ? undefined : v),
 8→);
 9→
10→const extractionEntityBaseSchema = z.object({
11→  tempId: z.string().min(1),
12→  kind: z.enum(["project", "feature", "task", "decision", "question"]),
13→  text: z.string().min(3).max(200),
14→  confidence: z.number().min(0).max(1),
15→  evidence: z.string().min(1),
16→  category: extractionCategorySchema,
17→}).strict();
18→
19→const extractionEntityWithAssigneeSchema = extractionEntityBaseSchema.extend({
20→  assignee_name: z.string().min(1),
21→}).strict();
22→
23→const extractionEntityWithResolvedFromSchema = extractionEntityBaseSchema.extend({
24→  resolvedFromMessageId: z.string().min(1),
25→}).strict();
26→
27→const extractionEntityWithAssigneeAndResolvedFromSchema = extractionEntityBaseSchema.extend({
28→  assignee_name: z.string().min(1),
29→  resolvedFromMessageId: z.string().min(1),
30→}).strict();
31→
32→const extractionEntitySchema = z.union([
33→  extractionEntityBaseSchema,
34→  extractionEntityWithAssigneeSchema,
35→  extractionEntityWithResolvedFromSchema,
36→  extractionEntityWithAssigneeAndResolvedFromSchema,
37→]);
38→
39→export const extractionRelationshipSchema = z.object({
40→  kind: z.string().min(1),
41→  fromTempId: z.string().min(1),
42→  toTempId: z.string().min(1),
43→  confidence: z.number().min(0).max(1),
44→  fromText: z.string().min(1),
45→  toText: z.string().min(1),
46→}).strict();
47→
48→export const extractionResultSchema = z.object({
49→  entities: z.array(extractionEntitySchema),
50→  relationships: z.array(extractionRelationshipSchema),
51→  tools: z.array(z.string().min(1)),
52→}).strict();
53→
54→export type ExtractionPromptEntity = z.infer<typeof extractionEntitySchema>;
55→export type ExtractionPromptRelationship = z.infer<typeof extractionRelationshipSchema>;
56→export type ExtractionPromptOutput = z.infer<typeof extractionResultSchema>;
57→
58→export function parseExtractionOutput(payload: unknown):
59→  | { ok: true; data: ExtractionPromptOutput }
60→  | { ok: false; error: string } {
61→  const result = extractionResultSchema.safeParse(payload);
62→  if (result.success) {
63→    return { ok: true, data: result.data };
64→  }
65→
66→  return {
67→    ok: false,
68→    error: result.error.issues[0]?.message ?? "Invalid extraction payload",
69→  };
70→}
