437→function uniqueCandidateRows(rows: CandidateEntityRow[]): CandidateEntityRow[] {
438→  const byId = new Map<string, CandidateEntityRow>();
439→  for (const row of rows) {
440→    byId.set(row.id.id as string, row);
441→  }
442→  return [...byId.values()];
443→}
