465→export function normalizeRelationshipKind(value: string): string {
466→  return value
467→    .trim()
468→    .replace(/[^a-zA-Z0-9]+/g, "_")
469→    .replace(/_+/g, "_")
470→    .replace(/^_/, "")
471→    .replace(/_$/, "")
472→    .toUpperCase();
473→}
