222→async function applyAssigneeReference(input: {
223→  surreal: Surreal;
224→  workspaceRecord: RecordId<"workspace", string>;
225→  entityRecord: GraphEntityRecord;
226→  entityKind: Exclude<EntityKind, "workspace" | "person" | "observation">;
227→  assigneeName: string;
228→  now: Date;
229→}): Promise<{ resolved: boolean; assigneeName: string }> {
230→  const assigneeName = input.assigneeName.trim();
231→  if (assigneeName.length === 0) {
232→    return { resolved: true, assigneeName };
233→  }
234→
235→  const personRecord = await findWorkspacePersonByName({
236→    surreal: input.surreal,
237→    workspaceRecord: input.workspaceRecord,
238→    personName: assigneeName,
239→  });
240→
241→  const patch = resolvePersonAttributionPatch({
242→    targetKind: input.entityKind,
243→    assigneeName,
244→    ...(personRecord ? { personRecordId: personRecord.id as string } : {}),
245→  });
246→
247→  if (patch.kind === "feature") {
248→    if (patch.field === "owner" && personRecord) {
249→      await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
250→        owner: personRecord,
251→        updated_at: input.now,
252→      });
253→      return { resolved: true, assigneeName };
254→    }
255→
256→    await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
257→      owner_name: patch.value,
258→      updated_at: input.now,
259→    });
260→    return { resolved: false, assigneeName };
261→  }
262→
263→  if (patch.kind === "task") {
264→    if (patch.field === "owner" && personRecord) {
265→      await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
266→        owner: personRecord,
267→        updated_at: input.now,
268→      });
269→      return { resolved: true, assigneeName };
270→    }
271→
272→    await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
273→      owner_name: patch.value,
274→      updated_at: input.now,
275→    });
276→    return { resolved: false, assigneeName };
277→  }
278→
279→  if (patch.kind === "decision") {
280→    if (patch.field === "decided_by" && personRecord) {
281→      await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
282→        decided_by: personRecord,
283→        updated_at: input.now,
284→      });
285→      return { resolved: true, assigneeName };
286→    }
287→
288→    await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
289→      decided_by_name: patch.value,
290→      updated_at: input.now,
291→    });
292→    return { resolved: false, assigneeName };
293→  }
294→
295→  if (patch.field === "assigned_to" && personRecord) {
296→    await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
297→      assigned_to: personRecord,
298→      updated_at: input.now,
299→    });
300→    return { resolved: true, assigneeName };
301→  }
302→
303→  await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
304→    assigned_to_name: patch.value,
305→    updated_at: input.now,
306→  });
307→  return { resolved: false, assigneeName };
308→}
