310→export async function appendExtractedTools(
311→  surreal: Surreal,
312→  workspaceRecord: RecordId<"workspace", string>,
313→  extractedTools: string[],
314→  now: Date,
315→): Promise<void> {
316→  const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
317→  if (extractedTools.length > 0 && dedupedTools.length > 0) {
318→    await appendWorkspaceTools(surreal, workspaceRecord, dedupedTools, now);
319→  }
