  1→import { useEffect, useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import type { EntityCategory, EntityDetailResponse, EntityKind } from "../../../shared/contracts";
  4→import { ENTITY_CATEGORIES } from "../../../shared/contracts";
  5→import { CategoryBadge } from "./CategoryBadge";
  6→import { EntityBadge } from "./EntityBadge";
  7→import { RelationshipList } from "./RelationshipList";
  8→import { ProvenanceSection } from "./ProvenanceSection";
  9→import { useViewState } from "../../stores/view-state";
 10→import { confirmDecision, overrideDecision, markTaskComplete } from "../../graph/actions";
 11→
 12→const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);
 13→
 14→export function EntityDetailPanel({
 15→  entityId,
 16→  workspaceId,
 17→  onClose,
 18→  onEntityClick,
 19→}: {
 20→  entityId: string;
 21→  workspaceId: string;
 22→  onClose: () => void;
 23→  onEntityClick: (entityId: string) => void;
 24→}) {
 25→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 26→  const [loading, setLoading] = useState(true);
 27→  const [error, setError] = useState<string | undefined>();
 28→  const [actionPending, setActionPending] = useState(false);
 29→  const navigateToChat = useViewState((s) => s.navigateToChat);
 30→  const navigate = useNavigate();
 31→
 32→  useEffect(() => {
 33→    setLoading(true);
 34→    setError(undefined);
 35→
 36→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 37→      .then(async (response) => {
 38→        if (!response.ok) {
 39→          const body = await response.text();
 40→          throw new Error(body);
 41→        }
 42→        return response.json() as Promise<EntityDetailResponse>;
 43→      })
 44→      .then((data) => {
 45→        setDetail(data);
 46→        setLoading(false);
 47→      })
 48→      .catch((err) => {
 49→        setError(err instanceof Error ? err.message : "Failed to load entity");
 50→        setLoading(false);
 51→      });
 52→  }, [entityId, workspaceId]);
 53→
 54→  function handleJumpToMessage(messageId: string) {
 55→    navigateToChat(messageId);
 56→    void navigate({ to: "/" });
 57→  }
 58→
 59→  async function handleConfirm() {
 60→    if (!detail || actionPending) return;
 61→    setActionPending(true);
 62→    try {
 63→      await confirmDecision(workspaceId, entityId);
 64→      setDetail((prev) =>
 65→        prev
 66→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 67→          : prev,
 68→      );
 69→    } finally {
 70→      setActionPending(false);
 71→    }
 72→  }
 73→
 74→  async function handleOverride() {
 75→    if (!detail || actionPending) return;
 76→    const newSummary = window.prompt("New decision summary:");
 77→    if (!newSummary) return;
 78→    setActionPending(true);
 79→    try {
 80→      await overrideDecision(workspaceId, entityId, newSummary);
 81→      setDetail((prev) =>
 82→        prev
 83→          ? {
 84→              ...prev,
 85→              entity: {
 86→                ...prev.entity,
 87→                name: newSummary,
 88→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
 89→              },
 90→            }
 91→          : prev,
 92→      );
 93→    } finally {
 94→      setActionPending(false);
 95→    }
 96→  }
 97→
 98→  async function handleComplete() {
 99→    if (!detail || actionPending) return;
100→    setActionPending(true);
101→    try {
102→      await markTaskComplete(workspaceId, entityId);
103→      setDetail((prev) =>
104→        prev
105→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
106→          : prev,
107→      );
108→    } finally {
109→      setActionPending(false);
110→    }
111→  }
112→
113→  if (loading) {
114→    return (
115→      <aside className="entity-detail-panel">
116→        <p className="entity-detail-meta">Loading...</p>
117→      </aside>
118→    );
119→  }
120→
121→  if (error || !detail) {
122→    return (
123→      <aside className="entity-detail-panel">
124→        <div className="entity-detail-header">
125→          <p className="entity-detail-meta">{error ?? "Entity not found"}</p>
126→          <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
127→        </div>
128→      </aside>
129→    );
130→  }
131→
132→  const kind = detail.entity.kind as EntityKind;
133→  const status = (detail.entity.data.status as string | undefined) ?? "";
134→  const rationale = detail.entity.data.rationale as string | undefined;
135→
136→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
137→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
138→  const showComplete = kind === "task" && status !== "done";
139→
140→  return (
141→    <aside className="entity-detail-panel">
142→      <div className="entity-detail-header">
143→        <div>
144→          <EntityBadge kind={kind} />
145→          <h3>{detail.entity.name}</h3>
146→        </div>
147→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
148→      </div>
149→
150→      <div className="entity-detail-section">
151→        <h4>Metadata</h4>
152→        <dl className="entity-detail-meta">
153→          {status ? (
154→            <>
155→              <dt>Status</dt>
156→              <dd>{status}</dd>
157→            </>
158→          ) : undefined}
159→          {typeof detail.entity.data.category === "string" && (ENTITY_CATEGORIES as readonly string[]).includes(detail.entity.data.category) ? (
160→            <>
161→              <dt>Category</dt>
162→              <dd><CategoryBadge category={detail.entity.data.category as EntityCategory} /></dd>
163→            </>
164→          ) : undefined}
165→          {detail.entity.data.confidence !== undefined ? (
166→            <>
167→              <dt>Confidence</dt>
168→              <dd>{(detail.entity.data.confidence as number).toFixed(2)}</dd>
169→            </>
170→          ) : undefined}
171→          {detail.entity.data.created_at ? (
172→            <>
173→              <dt>Created</dt>
174→              <dd>{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
175→            </>
176→          ) : undefined}
177→          {detail.entity.data.owner_name ? (
178→            <>
179→              <dt>Owner</dt>
180→              <dd>{detail.entity.data.owner_name as string}</dd>
181→            </>
182→          ) : undefined}
183→          {detail.entity.data.priority ? (
184→            <>
185→              <dt>Priority</dt>
186→              <dd>{detail.entity.data.priority as string}</dd>
187→            </>
188→          ) : undefined}
189→        </dl>
190→      </div>
191→
192→      {rationale ? (
193→        <div className="entity-detail-section">
194→          <h4>Rationale</h4>
195→          <p className="entity-detail-meta">{rationale}</p>
196→        </div>
197→      ) : undefined}
198→
199→      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />
200→
201→      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />
202→
203→      {(showConfirm || showOverride || showComplete) ? (
204→        <div className="entity-detail-actions">
205→          {showConfirm ? (
206→            <button type="button" disabled={actionPending} onClick={handleConfirm}>
207→              Confirm
208→            </button>
209→          ) : undefined}
210→          {showOverride ? (
211→            <button type="button" disabled={actionPending} onClick={handleOverride}>
212→              Override
213→            </button>
214→          ) : undefined}
215→          {showComplete ? (
216→            <button type="button" disabled={actionPending} onClick={handleComplete}>
217→              Mark Complete
218→            </button>
219→          ) : undefined}
220→        </div>
221→      ) : undefined}
222→    </aside>
223→  );
224→}
