858→export async function searchEntitiesByEmbedding(input: {
859→  surreal: Surreal;
860→  workspaceRecord: RecordId<"workspace", string>;
861→  queryEmbedding: number[];
862→  kinds?: SearchEntityKind[];
863→  projectRecord?: RecordId<"project", string>;
864→  limit: number;
865→}): Promise<RankedEntity[]> {
866→  const candidates = await listScopedEntityCandidates({
867→    surreal: input.surreal,
868→    workspaceRecord: input.workspaceRecord,
869→    kinds: input.kinds,
870→    projectRecord: input.projectRecord,
871→    candidateLimit: Math.max(input.limit * 20, 120),
872→  });
873→
874→  const rows = candidates
875→    .map((candidate) => ({
876→      candidate,
877→      score: candidate.embedding ? cosineSimilarity(input.queryEmbedding, candidate.embedding) : -1,
878→    }))
879→    .filter((row) => row.score > 0)
880→    .sort((a, b) => b.score - a.score)
881→    .slice(0, input.limit);
