883→  return rows.map((row) => ({
884→    id: toRecordIdString(row.candidate.id),
885→    kind: row.candidate.kind,
886→    name: row.candidate.name,
887→    score: row.score,
888→    ...(row.candidate.status ? { status: row.candidate.status } : {}),
