892→export async function listEntityNeighbors(input: {
893→  surreal: Surreal;
894→  workspaceRecord: RecordId<"workspace", string>;
895→  entityRecord: GraphEntityRecord;
896→  limit: number;
897→}): Promise<EntityNeighbor[]> {
898→  const [rows] = await input.surreal
899→    .query<[Array<{ in: GraphEntityRecord; out: GraphEntityRecord; kind: string; confidence: number; extracted_at: string | Date }>]>(
900→      [
901→        "SELECT `in`, out, kind, confidence, extracted_at",
902→        "FROM entity_relation",
903→        "WHERE `in` = $entity OR out = $entity",
904→        "ORDER BY extracted_at DESC",
905→        "LIMIT $limit;",
906→      ].join(" "),
907→      { entity: input.entityRecord, limit: input.limit },
908→    )
909→    .collect<[Array<{ in: GraphEntityRecord; out: GraphEntityRecord; kind: string; confidence: number; extracted_at: string | Date }>]>() ;
910→
911→  const neighbors: EntityNeighbor[] = [];
912→
913→  for (const row of rows) {
914→    const direction = toRecordIdString(row.in) === toRecordIdString(input.entityRecord) ? "outgoing" : "incoming";
915→    const neighborRecord = direction === "outgoing" ? row.out : row.in;
916→
917→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, neighborRecord);
918→    if (!scoped) {
919→      continue;
920→    }
921→
922→    const name = await readEntityName(input.surreal, neighborRecord);
923→    if (!name) {
924→      continue;
925→    }
926→
927→    neighbors.push({
928→      id: toRecordIdString(neighborRecord),
929→      kind: neighborRecord.table.name as GraphEntityTable,
930→      name,
931→      relationKind: row.kind,
932→      direction,
933→      confidence: row.confidence,
934→    });
935→  }
936→
937→  return neighbors;
938→}
