258→  confidence: number,
259→  now: Date,
260→  embedding?: number[],
261→  sourceMessageRecord?: RecordId<"message", string>,
262→  category?: string,
263→): Record<string, unknown> {
264→  if (kind === "project") {
265→    return {
266→      name: text,
267→      status: "active",
268→      ...(embedding ? { embedding } : {}),
269→      created_at: now,
270→      updated_at: now,
271→    };
272→  }
273→
274→  if (kind === "feature") {
275→    return {
276→      name: text,
277→      status: "active",
278→      ...(embedding ? { embedding } : {}),
279→      created_at: now,
280→      updated_at: now,
281→    };
282→  }
283→
284→  if (kind === "task") {
285→    return {
286→      title: text,
287→      status: "open",
288→      extraction_confidence: confidence,
289→      extracted_at: now,
290→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
291→      ...(embedding ? { embedding } : {}),
292→      ...(category ? { category } : {}),
293→      created_at: now,
294→      updated_at: now,
295→    };
296→  }
297→
298→  if (kind === "decision") {
299→    return {
300→      summary: text,
301→      status: "extracted",
302→      extraction_confidence: confidence,
303→      extracted_at: now,
304→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
305→      ...(embedding ? { embedding } : {}),
306→      ...(category ? { category } : {}),
307→      created_at: now,
308→      updated_at: now,
309→    };
310→  }
311→
312→  // question (fallthrough)
313→  return {
314→    text,
315→    status: "open",
316→    extraction_confidence: confidence,
317→    extracted_at: now,
318→    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
319→    ...(embedding ? { embedding } : {}),
320→    ...(category ? { category } : {}),
321→    created_at: now,
322→    updated_at: now,
323→  };
324→}
