375→      sourceMessageId: toRecordIdString(row.in),
376→    });
377→    seen.add(entityKey);
378→  }
379→
380→  // Merge inherited entities from parent conversation when branch has sparse context
381→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
382→    const [inheritedRows] = await input.surreal
383→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
384→        [
385→          "SELECT `in`, out, confidence, extracted_at",
386→          "FROM extraction_relation",
387→          "WHERE out IN $entityIds",
388→          "ORDER BY extracted_at DESC",
389→          "LIMIT $limit;",
390→        ].join(" "),
391→        { entityIds: input.inheritedEntityIds, limit: input.limit },
392→      )
393→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
394→
395→    for (const row of inheritedRows) {
396→      const table = row.out.table.name as GraphEntityTable;
397→      if (
398→        table !== "workspace" &&
399→        table !== "project" &&
400→        table !== "person" &&
401→        table !== "feature" &&
402→        table !== "task" &&
403→        table !== "decision" &&
404→        table !== "question"
405→      ) {
406→        continue;
407→      }
408→
409→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
410→      if (seen.has(entityKey)) continue;
411→
412→      const name = await readEntityName(input.surreal, row.out);
413→      if (!name) continue;
414→
415→      items.push({
416→        id: toRecordIdString(row.out),
417→        kind: table,
418→        name,
419→        confidence: row.confidence,
420→        sourceMessageId: toRecordIdString(row.in),
421→      });
422→      seen.add(entityKey);
423→    }
424→  }
425→
426→  return items;
427→}
