430→  surreal: Surreal;
431→  workspaceRecord: RecordId<"workspace", string>;
432→  limit: number;
433→}): Promise<WorkspaceProjectSummary[]> {
434→  const projectRows = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
435→  const limited = projectRows.slice(0, input.limit);
436→
437→  const counts = await Promise.all(
438→    limited.map(async (project) => {
439→      const [countRows] = await input.surreal
440→        .query<[Array<{ count: number }>]>(
441→          [
442→            "SELECT count() AS count",
443→            "FROM task",
444→            "WHERE status != 'done'",
445→            "AND (",
446→            "  id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
447→            "  OR id IN (",
448→            "    SELECT VALUE out",
449→            "    FROM has_task",
450→            "    WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
451→            "  )",
452→            ");",
453→          ].join(" "),
454→          { project: project.id },
455→        )
456→        .collect<[Array<{ count: number }>]>();
457→
458→      return {
459→        id: toRecordIdString(project.id),
460→        name: project.name,
461→        activeTaskCount: countRows[0]?.count ?? 0,
462→      } satisfies WorkspaceProjectSummary;
463→    }),
464→  );
465→
466→  return counts;
467→}
