 1→import type { ReagraphNode, ReagraphEdge, GraphResponse, EntityKind } from "../../shared/contracts";
 2→import type { GraphViewRawResult } from "./queries";
 3→
 4→// Resolved hex values for OKLCH entity colors — Three.js/WebGL cannot parse CSS variables.
 5→export function entityColor(kind: EntityKind): string {
 6→  switch (kind) {
 7→    case "project": return "#3b82f6";   // oklch(0.65 0.15 250)
 8→    case "feature": return "#14b8a6";   // oklch(0.65 0.15 170)
 9→    case "task": return "#22c55e";      // oklch(0.70 0.15 145)
10→    case "decision": return "#eab308";  // oklch(0.70 0.15 55)
11→    case "question": return "#a855f7";  // oklch(0.65 0.15 300)
12→    case "observation": return "#ef4444";
13→    case "person": return "#f97316";    // oklch(0.65 0.15 25)
14→    case "workspace": return "#3b82f6";
15→  }
16→}
17→
18→function titleCase(s: string): string {
19→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
20→}
21→
22→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
23→  const connectionCounts = new Map<string, number>();
24→  for (const edge of raw.edges) {
25→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
26→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
27→  }
28→
29→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
30→    const kind = entity.kind as EntityKind;
31→    const kindBoost = kind === "project" ? 20
32→      : kind === "feature" ? 10
33→      : kind === "person" ? 8
34→      : 0;
35→    return {
36→      id: entity.id,
37→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
38→      fill: entityColor(kind),
39→      data: {
40→        kind,
41→        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
42→        status: undefined,
43→      },
44→    };
45→  });
46→
47→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
48→    id: edge.id,
49→    source: edge.fromId,
50→    target: edge.toId,
51→    label: titleCase(edge.kind.replace(/_/g, " ")),
52→    data: {
53→      type: edge.kind,
54→      confidence: edge.confidence,
55→    },
56→  }));
57→
58→  return { nodes, edges };
59→}
