624→export async function resolveWorkspaceFeatureRecord(input: {
625→  surreal: Surreal;
626→  workspaceRecord: RecordId<"workspace", string>;
627→  featureInput: string;
628→}): Promise<RecordId<"feature", string>> {
629→  const featureInput = input.featureInput.trim();
630→  if (featureInput.length === 0) {
631→    throw new Error("feature identifier is required");
632→  }
633→
634→  if (featureInput.includes(":")) {
635→    const featureRecord = parseRecordIdString(featureInput, ["feature"]);
636→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, featureRecord);
637→    if (!scoped) {
638→      throw new Error("feature is not linked to this workspace");
639→    }
640→    return featureRecord;
641→  }
642→
643→  const [rows] = await input.surreal
644→    .query<[Array<{ id: RecordId<"feature", string>; name: string }>]>(
645→      [
646→        "SELECT id, name",
647→        "FROM feature",
648→        "WHERE id IN (",
649→        "  SELECT VALUE out",
650→        "  FROM has_feature",
651→        "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
652→        ");",
653→      ].join(" "),
654→      {
655→        workspace: input.workspaceRecord,
656→      },
657→    )
658→    .collect<[Array<{ id: RecordId<"feature", string>; name: string }>]>();
659→
660→  const normalized = normalizeSearchValue(featureInput);
661→  const exactMatch = rows.find((row) => normalizeSearchValue(row.name) === normalized);
662→  if (exactMatch) {
663→    return exactMatch.id;
664→  }
665→
666→  const fuzzy = rows.filter((row) => normalizeSearchValue(row.name).includes(normalized));
667→  if (fuzzy.length === 1) {
668→    return fuzzy[0].id;
669→  }
670→
671→  if (fuzzy.length > 1) {
672→    throw new Error(`feature input is ambiguous: ${fuzzy.map((row) => row.name).join(", ")}`);
673→  }
674→
675→  throw new Error(`feature not found in workspace: ${featureInput}`);
676→}
