      },
    )
    .collect<[Array<{ id: RecordId<"feature", string>; name: string }>]>();

  const normalized = normalizeSearchValue(featureInput);
  const exactMatch = rows.find((row) => normalizeSearchValue(row.name) === normalized);
  if (exactMatch) {
