  1→import { afterAll, beforeAll } from "bun:test";
  2→import { readFileSync } from "node:fs";
  3→import { join } from "node:path";
  4→import { Surreal } from "surrealdb";
  5→
  6→export type SmokeTestRuntime = {
  7→  baseUrl: string;
  8→  surreal: Surreal;
  9→  namespace: string;
 10→  database: string;
 11→  port: number;
 12→};
 13→
 14→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 15→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 16→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 17→const smokePortBase = Number(process.env.SMOKE_PORT_BASE ?? "3100");
 18→
 19→export function setupSmokeSuite(suiteName: string): () => SmokeTestRuntime {
 20→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 21→  const namespace = `smoke_${runId}`;
 22→  const suiteSlug = suiteName
 23→    .toLowerCase()
 24→    .replace(/[^a-z0-9]+/g, "_")
 25→    .replace(/^_+|_+$/g, "");
 26→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 27→
 28→  let runtime: SmokeTestRuntime | undefined;
 29→  let serverProcess: ReturnType<typeof Bun.spawn> | undefined;
 30→  let setupSucceeded = false;
 31→
 32→  beforeAll(async () => {
 33→    const port = process.env.SMOKE_PORT
 34→      ? Number(process.env.SMOKE_PORT)
 35→      : smokePortBase + Math.floor(Math.random() * 20000);
 36→    if (!Number.isFinite(port) || port <= 0) {
 37→      throw new Error(`Invalid smoke test port value: ${port}`);
 38→    }
 39→    const baseUrl = `http://127.0.0.1:${port}`;
 40→
 41→    const surreal = new Surreal();
 42→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 43→    await withTimeout(
 44→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 45→      10_000,
 46→      "authenticate with SurrealDB",
 47→    );
 48→
 49→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 50→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 51→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 52→    await withTimeout(
 53→      () => surreal.use({ namespace, database }),
 54→      10_000,
 55→      "switch to test namespace/database",
 56→    );
 57→
 58→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 59→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
 60→
 61→    serverProcess = Bun.spawn(["bun", "run", "app/server.ts"], {
 62→      cwd: process.cwd(),
 63→      env: {
 64→        ...process.env,
 65→        PORT: String(port),
 66→        SURREAL_NAMESPACE: namespace,
 67→        SURREAL_DATABASE: database,
 68→      },
 69→      stdout: "pipe",
 70→      stderr: "pipe",
 71→    });
 72→
 73→    await waitForHealth(baseUrl, serverProcess, 15_000);
 74→    runtime = { baseUrl, surreal, namespace, database, port };
 75→    setupSucceeded = true;
 76→  }, 60_000);
 77→
 78→  afterAll(async () => {
 79→    if (serverProcess) {
 80→      serverProcess.kill();
 81→      await serverProcess.exited;
 82→    }
 83→
 84→    if (!runtime) {
 85→      return;
 86→    }
 87→
 88→    if (setupSucceeded) {
 89→      try {
 90→        await withTimeout(() => runtime.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
 91→      } catch {
 92→        // Best effort cleanup.
 93→      }
 94→
 95→      try {
 96→        await withTimeout(() => runtime.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
 97→      } catch {
 98→        // Best effort cleanup.
 99→      }
100→    }
101→
102→    await withTimeout(() => runtime.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
103→  }, 20_000);
104→
105→  return () => {
106→    if (!runtime) {
107→      throw new Error("Smoke runtime requested before suite setup completed");
108→    }
109→    return runtime;
110→  };
111→}
112→
113→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
114→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
115→  if (!response.ok || !response.body) {
116→    throw new Error(`Failed to open SSE stream (${response.status})`);
117→  }
118→
119→  const reader = response.body.getReader();
120→  const decoder = new TextDecoder();
121→  const events: T[] = [];
122→  let buffer = "";
123→
124→  const timeout = setTimeout(() => {
125→    void reader.cancel();
126→  }, timeoutMs);
127→
128→  try {
129→    while (true) {
130→      const { value, done } = await reader.read();
131→      if (done) {
132→        break;
133→      }
134→
135→      buffer += decoder.decode(value, { stream: true });
136→      const segments = buffer.split("\n\n");
137→      buffer = segments.pop() ?? "";
138→
139→      for (const segment of segments) {
140→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
141→        if (!dataLine) {
142→          continue;
143→        }
144→
145→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
146→        events.push(event);
147→
148→        if (event.type === "error") {
149→          const errorText = (event as { error?: string }).error;
150→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
151→        }
152→
153→        if (event.type === "done") {
154→          return events;
155→        }
156→      }
157→    }
158→  } finally {
159→    clearTimeout(timeout);
160→    reader.releaseLock();
161→  }
162→
163→  return events;
164→}
165→
166→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
167→  const response = await fetch(url, init);
168→  if (!response.ok) {
169→    const body = await response.text();
170→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
171→  }
172→
173→  return (await response.json()) as T;
174→}
175→
176→async function waitForHealth(url: string, process: ReturnType<typeof Bun.spawn>, timeoutMs: number): Promise<void> {
177→  const start = Date.now();
178→
179→  while (Date.now() - start < timeoutMs) {
180→    if (typeof process.exitCode === "number") {
181→      throw new Error(`Smoke server exited early with code ${process.exitCode}`);
182→    }
183→
184→    try {
185→      const response = await fetch(`${url}/healthz`);
186→      if (response.ok) {
187→        return;
188→      }
189→    } catch {
190→      // Keep polling.
191→    }
192→
193→    await Bun.sleep(200);
194→  }
195→
196→  throw new Error(`Timed out waiting for smoke server health at ${url}/healthz`);
197→}
198→
199→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
200→  return await Promise.race([
201→    callback(),
202→    new Promise<T>((_, reject) => {
203→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
204→    }),
205→  ]);
206→}
