 1→import { describe, expect, it } from "bun:test";
 2→import { setupSmokeSuite } from "./smoke-test-kit";
 3→
 4→const getRuntime = setupSmokeSuite("logging");
 5→
 6→const logFilePath = process.env.SMOKE_LOG_FILE;
 7→
 8→describe("logging smoke", () => {
 9→  it("sets and forwards request ids for health checks and client errors", async () => {
10→    const { baseUrl } = getRuntime();
11→
12→    const generatedRequestId = await assertRequestIdGenerated(baseUrl);
13→    const forwardedRequestId = `smoke-${crypto.randomUUID()}`;
14→    await assertRequestIdForwarded(baseUrl, forwardedRequestId);
15→    const invalidRequestId = await assertRequestIdOnClientError(baseUrl);
16→
17→    if (logFilePath && logFilePath.trim().length > 0) {
18→      await assertLogFileShape(logFilePath, [generatedRequestId, forwardedRequestId, invalidRequestId]);
19→    }
20→  }, 30_000);
21→});
22→
23→async function assertRequestIdGenerated(baseUrl: string): Promise<string> {
24→  const response = await fetch(`${baseUrl}/healthz`);
25→  expect(response.ok).toBe(true);
26→
27→  const requestId = response.headers.get("x-request-id");
28→  expect(typeof requestId).toBe("string");
29→  if (typeof requestId !== "string") {
30→    throw new Error("x-request-id missing on /healthz");
31→  }
32→  expect(requestId.length).toBeGreaterThan(0);
33→
34→  const payload = (await response.json()) as { status: string };
35→  expect(payload.status).toBe("ok");
36→
37→  return requestId;
38→}
39→
40→async function assertRequestIdForwarded(baseUrl: string, requestId: string): Promise<void> {
41→  const response = await fetch(`${baseUrl}/healthz`, {
42→    headers: {
43→      "x-request-id": requestId,
44→    },
45→  });
46→
47→  expect(response.ok).toBe(true);
48→  expect(response.headers.get("x-request-id")).toBe(requestId);
49→}
50→
51→async function assertRequestIdOnClientError(baseUrl: string): Promise<string> {
52→  const response = await fetch(`${baseUrl}/api/entities/search`);
53→  expect(response.status).toBe(400);
54→
55→  const requestId = response.headers.get("x-request-id");
56→  expect(typeof requestId).toBe("string");
57→  if (typeof requestId !== "string") {
58→    throw new Error("x-request-id missing on 4xx response");
59→  }
60→  expect(requestId.length).toBeGreaterThan(0);
61→
62→  const payload = (await response.json()) as { error: string };
63→  expect(typeof payload.error).toBe("string");
64→  expect(payload.error.length).toBeGreaterThan(0);
65→
66→  return requestId;
67→}
68→
69→async function assertLogFileShape(logPath: string, requestIds: string[]): Promise<void> {
70→  const file = Bun.file(logPath);
71→  const exists = await file.exists();
72→  expect(exists).toBe(true);
73→
74→  const content = await file.text();
75→  const lines = content
76→    .split("\n")
77→    .map((line) => line.trim())
78→    .filter((line) => line.length > 0);
79→  expect(lines.length).toBeGreaterThan(0);
80→
81→  const rows: Array<Record<string, unknown>> = [];
82→  for (const line of lines) {
83→    const parsed = JSON.parse(line) as Record<string, unknown>;
84→    expect(typeof parsed.timestamp).toBe("string");
85→    expect(typeof parsed.level).toBe("string");
86→    expect(typeof parsed.event).toBe("string");
87→    rows.push(parsed);
88→  }
89→
90→  for (const requestId of requestIds) {
91→    const requestRows = rows.filter((row) => row.requestId === requestId);
92→    expect(requestRows.length).toBeGreaterThan(0);
93→    expect(requestRows.some((row) => row.event === "http.request.completed")).toBe(true);
94→  }
95→}
